// Case A: pneuma's voice-flac-pipeline accepts in-memory Int16Array
// (sourcePcm) and a VocoderPredictor that returns Float32Array, so the
// bridge can run end-to-end without any temp-file workaround. These
// tests exercise the round-trip and validate the declared API surface.
//
// The bridge currently passes empty phonemeIds + makeZeroPredictor (the
// audio->phoneme front-end is the documented upstream gap); under that
// scaffold the residual carries the full source so the round-trip is
// lossless. When a real phoneme extractor lands, swap fixtures and add
// a noise-robustness assertion.

import { describe, it, expect } from "vitest";
import {
  recoverAudioViaPneuma,
  type PneumaAudioRecoverArgs,
  type PneumaAudioRecoverResult,
} from "../src/audio-pneuma-bridge";

function lcg(seed: number) {
  let s = seed >>> 0;
  return () => {
    s = (s * 1103515245 + 12345) & 0x7fffffff;
    return s / 0x7fffffff - 0.5;
  };
}

function whisperFixture(
  sampleRate: number,
  duration: number,
  seed: number,
): { clean: Float32Array; noisy: Float32Array } {
  const n = Math.floor(sampleRate * duration);
  const clean = new Float32Array(n);
  const noisy = new Float32Array(n);
  const rand = lcg(seed);
  for (let i = 0; i < n; i++) {
    const t = i / sampleRate;
    const inVoice = t > duration * 0.25 && t < duration * 0.75;
    let signal = 0;
    if (inVoice) {
      signal =
        0.3 * Math.sin(2 * Math.PI * 500 * t) +
        0.2 * Math.sin(2 * Math.PI * 1500 * t);
    }
    const noise = 0.08 * rand();
    clean[i] = signal;
    noisy[i] = signal + noise;
  }
  return { clean, noisy };
}

describe("recoverAudioViaPneuma", () => {
  it("round-trips noisy audio through pneuma encode/decode with pre-denoise", async () => {
    const sampleRate = 16000;
    const duration = 1.0;
    const { noisy } = whisperFixture(sampleRate, duration, 42);

    const result = await recoverAudioViaPneuma({
      audio: noisy,
      sampleRate,
      preDenoise: true,
    });

    expect(result.audio).toBeInstanceOf(Float32Array);
    expect(result.audio.length).toBeGreaterThan(0);
    expect(result.preDenoised).toBe(true);
    expect(result.sampleRate).toBe(sampleRate);
    expect(result.packetSize).toBeGreaterThan(0);
    // Lossless tier with full residual is below ~700 kbps for raw 16-bit
    // mono @ 16kHz (=256 kbps). This bound is generous.
    expect(result.bitsPerSecond).toBeLessThan(700000);
    expect(result.decodeTierRequested).toBe(3);
    expect(result.decodeTierUsed).toBe(3);
    // All samples must be finite.
    for (let i = 0; i < result.audio.length; i++) {
      expect(Number.isFinite(result.audio[i]!)).toBe(true);
    }
  });

  it("honours preDenoise=false (preDenoised flag is false)", async () => {
    const sampleRate = 16000;
    const { noisy } = whisperFixture(sampleRate, 1.0, 7);

    const result = await recoverAudioViaPneuma({
      audio: noisy,
      sampleRate,
      preDenoise: false,
    });

    expect(result.preDenoised).toBe(false);
    expect(result.audio.length).toBeGreaterThan(0);
  });

  it("defaults preDenoise to true when omitted", async () => {
    const sampleRate = 16000;
    const { noisy } = whisperFixture(sampleRate, 1.0, 11);

    const result = await recoverAudioViaPneuma({
      audio: noisy,
      sampleRate,
    });

    expect(result.preDenoised).toBe(true);
  });

  it("forwards spectralSubtraction tuning to denoiseAudio", async () => {
    const sampleRate = 16000;
    const { noisy } = whisperFixture(sampleRate, 1.0, 13);

    const result = await recoverAudioViaPneuma({
      audio: noisy,
      sampleRate,
      preDenoise: true,
      spectralSubtraction: {
        oversubtractionFactor: 3.0,
        spectralFloor: 0.05,
        noiseFractionFrames: 0.15,
        nFft: 512,
        hopLength: 128,
      },
    });

    expect(result.preDenoised).toBe(true);
    expect(result.audio.length).toBeGreaterThan(0);
  });

  it("computes bitsPerSecond from packetSize and duration", async () => {
    const sampleRate = 16000;
    const duration = 1.0;
    const { noisy } = whisperFixture(sampleRate, duration, 17);

    const result = await recoverAudioViaPneuma({
      audio: noisy,
      sampleRate,
      preDenoise: false,
    });

    const expectedBps = (result.packetSize * 8) / duration;
    expect(result.bitsPerSecond).toBeCloseTo(expectedBps, 4);
  });

  it("decodeTier ceiling is reflected in result.decodeTierRequested", async () => {
    const sampleRate = 16000;
    const { noisy } = whisperFixture(sampleRate, 1.0, 19);

    const r1 = await recoverAudioViaPneuma({
      audio: noisy,
      sampleRate,
      preDenoise: false,
      decodeTier: 1,
    });
    expect(r1.decodeTierRequested).toBe(1);

    const r3 = await recoverAudioViaPneuma({
      audio: noisy,
      sampleRate,
      preDenoise: false,
      decodeTier: 3,
    });
    expect(r3.decodeTierRequested).toBe(3);
  });

  describe("API shape", () => {
    it("PneumaAudioRecoverArgs accepts the documented fields (compile-time check)", () => {
      const args: PneumaAudioRecoverArgs = {
        audio: new Float32Array(16),
        sampleRate: 16000,
        preDenoise: true,
        decodeTier: 2,
        spectralSubtraction: {
          oversubtractionFactor: 2.0,
          spectralFloor: 0.01,
          noiseFractionFrames: 0.1,
          nFft: 1024,
          hopLength: 256,
        },
      };
      expect(args.audio).toBeInstanceOf(Float32Array);
      expect(args.sampleRate).toBe(16000);
      expect(args.preDenoise).toBe(true);
      expect(args.decodeTier).toBe(2);
      expect(args.spectralSubtraction?.oversubtractionFactor).toBe(2.0);
    });

    it("PneumaAudioRecoverResult has the documented fields", async () => {
      const sampleRate = 16000;
      const { noisy } = whisperFixture(sampleRate, 1.0, 23);

      const result: PneumaAudioRecoverResult = await recoverAudioViaPneuma({
        audio: noisy,
        sampleRate,
        preDenoise: false,
      });

      expect(result).toHaveProperty("audio");
      expect(result).toHaveProperty("sampleRate");
      expect(result).toHaveProperty("preDenoised");
      expect(result).toHaveProperty("packetSize");
      expect(result).toHaveProperty("bitsPerSecond");
      expect(result).toHaveProperty("decodeTierRequested");
      expect(result).toHaveProperty("decodeTierUsed");
      expect(result.audio).toBeInstanceOf(Float32Array);
      expect(typeof result.sampleRate).toBe("number");
      expect(typeof result.preDenoised).toBe("boolean");
      expect(typeof result.packetSize).toBe("number");
      expect(typeof result.bitsPerSecond).toBe("number");
      expect(typeof result.decodeTierRequested).toBe("number");
      expect(typeof result.decodeTierUsed).toBe("number");
    });

    it("function returns a Promise", () => {
      const sampleRate = 16000;
      const audio = whisperFixture(sampleRate, 1.0, 29).noisy;
      const ret = recoverAudioViaPneuma({
        audio,
        sampleRate,
        preDenoise: false,
      });
      expect(ret).toBeInstanceOf(Promise);
      // Drain the promise to avoid unhandled-rejection noise.
      return ret.then((r) => expect(r.audio.length).toBeGreaterThan(0));
    });
  });

  describe("validation", () => {
    const sampleRate = 16000;
    const goodAudio = whisperFixture(sampleRate, 1.0, 1).noisy;

    it("throws on non-Float32Array audio", async () => {
      await expect(
        recoverAudioViaPneuma({
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          audio: [1, 2, 3] as any,
          sampleRate,
        }),
      ).rejects.toThrow(RangeError);
    });

    it("throws on empty audio", async () => {
      await expect(
        recoverAudioViaPneuma({
          audio: new Float32Array(0),
          sampleRate,
        }),
      ).rejects.toThrow(RangeError);
    });

    it("throws on zero sampleRate", async () => {
      await expect(
        recoverAudioViaPneuma({
          audio: goodAudio,
          sampleRate: 0,
        }),
      ).rejects.toThrow(RangeError);
    });

    it("throws on negative sampleRate", async () => {
      await expect(
        recoverAudioViaPneuma({
          audio: goodAudio,
          sampleRate: -16000,
        }),
      ).rejects.toThrow(RangeError);
    });

    it("throws on non-numeric sampleRate", async () => {
      await expect(
        recoverAudioViaPneuma({
          audio: goodAudio,
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          sampleRate: "16000" as any,
        }),
      ).rejects.toThrow(RangeError);
    });

    it("throws on invalid decodeTier", async () => {
      await expect(
        recoverAudioViaPneuma({
          audio: goodAudio,
          sampleRate,
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          decodeTier: 4 as any,
          preDenoise: false,
        }),
      ).rejects.toThrow(RangeError);
    });
  });
});
